import React from 'react';
import PeerCard from '../components/ui/PeerCard';
import './PeersPage.css';

const PeersPage = ({ peers, connectToPeer, loading }) => {
  return (
    <div className="peers-page fade-in">
      <div className="page-header">
        <h1 className="page-title">Network Peers</h1>
        <p className="muted">Discover and connect to devices on your local network</p>
      </div>

      <div className="peers-grid">
        {peers.length === 0 ? (
          <div className="empty-state">
            <span className="empty-icon">📡</span>
            <h3>No Peers Found</h3>
            <p>Scanning the local network... Make sure other devices are running PeerX.</p>
          </div>
        ) : (
          peers.map(peer => (
            <PeerCard 
              key={peer.peerId} 
              peer={peer} 
              onConnect={connectToPeer}
              isConnecting={loading}
            />
          ))
        )}
      </div>
    </div>
  );
};

export default PeersPage;
